**EX C — break/continue và label (20 phút)**
Tạo file: `03_control.go`
```go
// break/continue thuộc loop gần nhất
for i := 0; i < 3; i++ {
    for j := 0; j < 3; j++ {
        if j == 1 { continue }  // skip vòng j, không skip vòng i
        fmt.Println(i, j)
    }
}

// Named break để thoát vòng ngoài
outer:
for i := 0; i < 3; i++ {
    for j := 0; j < 3; j++ {
        if i+j == 3 { break outer }  // thoát cả vòng ngoài
        fmt.Println(i, j)
    }
}
// ❓ Khi nào nên dùng label? Có thể thay bằng gì?
```

