**BƯỚC 1 — Implement `convert` package + test (90 phút)**
File `convert/convert.go`:
```go
package convert
import (
    "fmt"
    "strconv"
)

// ParseFloat parses s to float64.
// Returns error if s is not a valid number.
func ParseFloat(s string) (float64, error) {
    v, err := strconv.ParseFloat(s, 64)
    if err != nil {
        return 0, fmt.Errorf("invalid number %q: %w", s, err)
    }
    return v, nil
}
```

File `convert/convert_test.go` (table-driven):
```go
package convert
import "testing"

func TestParseFloat(t *testing.T) {
    tests := []struct{
        input string
        want  float64
        wantErr bool
    }{
        {"3.14", 3.14, false},
        {"-1", -1, false},
        {"", 0, true},
        {"abc", 0, true},
        {"1e9", 1e9, false},
    }
    for _, tt := range tests {
        got, err := ParseFloat(tt.input)
        if (err != nil) != tt.wantErr {
            t.Errorf("ParseFloat(%q) error=%v, wantErr=%v", tt.input, err, tt.wantErr)
        }
        if !tt.wantErr && got != tt.want {
            t.Errorf("ParseFloat(%q) = %v, want %v", tt.input, got, tt.want)
        }
    }
}
```

