**EX C — Fixed-size Buffer Module (45 phút)**
File: `buffer/buffer.go`
```go
package buffer

// RingBuffer là fixed-size circular buffer để giữ N phần tử gần nhất.
type RingBuffer struct {
    data  [8]float64
    head  int
    count int
}

// Push thêm item. Nếu đầy thì overwrite cũ nhất.
func (r *RingBuffer) Push(v float64) {
    r.data[r.head % 8] = v
    r.head++
    if r.count < 8 { r.count++ }
}

// Average trả trung bình. Return 0 nếu chưa có data.
func (r *RingBuffer) Average() float64 {
    if r.count == 0 { return 0 }
    var sum float64
    for _, v := range r.data[:r.count] { sum += v }
    return sum / float64(r.count)
}
```
File: `buffer/buffer_test.go` — viết test cho Push và Average

