**Feature 2 — 12h/24h mode (30 phút)**
```go
type HourFormat int
const (
    Format24 HourFormat = iota
    Format12
)
func formatHour(h int, f HourFormat) (display int, ampm string) {
    if f == Format12 {
        if h == 0 { return 12, "AM" }
        if h < 12 { return h, "AM" }
        if h == 12 { return 12, "PM" }
        return h - 12, "PM"
    }
    return h, ""
}
```

