**BƯỚC 2 — Tách simulation step (45 phút)**
File: `sim/sim.go`
```go
package sim

type Ball struct {
    X, Y   float64
    VX, VY float64
}

// Step cập nhật trạng thái 1 tick. Bounds: [0, width] x [0, height].
func Step(b Ball, width, height float64) Ball {
    b.X += b.VX
    b.Y += b.VY
    // Reflect nếu chạm biên
    if b.X < 0 || b.X > width  { b.VX = -b.VX }
    if b.Y < 0 || b.Y > height { b.VY = -b.VY }
    return b  // return copy, không mutate!
}
```

File: `sim/sim_test.go`:
```go
func TestStepReflect(t *testing.T) {
