package main
import "fmt"

// ❌ BUG: a và b share backing array!
func aliasDemo() {
    original := []int{1, 2, 3, 4, 5}
    alias := original[1:3]    // alias = [2, 3], share backing array!

    alias[0] = 999
    fmt.Println(original)  // [1 999 3 4 5] — bị thay đổi!
}

// ✅ FIX: dùng copy để bứt hẳn
func safeCopy() {
    original := []int{1, 2, 3, 4, 5}
    independent := make([]int, 2)
    copy(independent, original[1:3])  // copy data

    independent[0] = 999
    fmt.Println(original)  // [1 2 3 4 5] — không đổi!
}

func main() {
    aliasDemo()
    safeCopy()
}
```
