**EX C — Preallocate vs Grow (30 phút)**
File: `03_preallocate.go`
```go
// So sánh:
// 1. grow dần (append không preallocate)
// 2. preallocate với make([]T, 0, n)
// 3. preallocate cả len (rồi index trực tiếp)

func buildSliceGrow(n int) []int {
    var s []int
    for i := 0; i < n; i++ {
        s = append(s, i*i)
    }
    return s
}

func buildSlicePrealloc(n int) []int {
    s := make([]int, 0, n)  // preallocate cap
    for i := 0; i < n; i++ {
        s = append(s, i*i)
    }
    return s
}
```
