**EX B — Re-implement từ đầu (60 phút)**
File: `finder/finder.go`
```go
package finder

import (
    "io/fs"
    "path/filepath"
)

// Result lưu kết quả scan một file.
type Result struct {
    Path    string
    Empty   bool
    Err     error  // non-nil nếu không đọc được
}

// FindEmpty trả danh sách tất cả file trong root.
// Nếu file rỗng: Result.Empty = true
// Nếu lỗi đọc: Result.Err = error (không dừng scan)
func FindEmpty(root string) ([]Result, error) {
    var results []Result
    err := filepath.WalkDir(root, func(path string, d fs.DirEntry, err error) error {
        if err != nil {
            // Lỗi access folder — ghi lại, tiếp tục
            results = append(results, Result{Path: path, Err: err})
            return nil  // không return err → tiếp tục scan
        }
        if d.IsDir() { return nil }

        info, err := d.Info()
        if err != nil {
            results = append(results, Result{Path: path, Err: err})
            return nil
        }
        results = append(results, Result{
            Path:  path,
            Empty: info.Size() == 0,
        })
        return nil
    })
    return results, err
}
```

