// Truncate truncates s to at most maxRunes runes, không cắt giữa multi-byte char.
func Truncate(s string, maxRunes int) string {
    count := 0
    for i := range s {  // i là byte index, nhưng range đúng
        if count == maxRunes {
            return s[:i]  // cắt tại byte boundary
        }
        count++
    }
    return s  // s ngắn hơn maxRunes
}

