)

// Wrap wraps text at maxWidth runes per line, splitting on spaces.
// Không cắt giữa rune; word dài hơn width — buộc xuống dòng mới.
func Wrap(text string, maxWidth int) string {
    words := strings.Fields(text)
    if len(words) == 0 { return "" }

    var lines []string
    currentLine := words[0]

    for _, word := range words[1:] {
        // Kiểm tra rùne width — không byte width!
        runeWidth := utf8.RuneCountInString(currentLine) + 1 + utf8.RuneCountInString(word)
        if runeWidth > maxWidth {
            lines = append(lines, currentLine)
            currentLine = word
        } else {
            currentLine += " " + word
        }
    }
    lines = append(lines, currentLine)
    return strings.Join(lines, "\n")
}
```

Test với text tiếng Việt có dấu:
```go
func TestWrapUnicode(t *testing.T) {
    text := "Chào bạn tịi Việt Nam"
    got := Wrap(text, 10)
    lines := strings.Split(got, "\n")
    for _, l := range lines {
        if utf8.RuneCountInString(l) > 10 {
            t.Errorf("line too long: %q (%d runes)", l, utf8.RuneCountInString(l))
        }
    }
}
```

