package structs

// FileStat giữ thông tin một file.
// Invariant: Path không rỗng; Size >= 0.
type FileStat struct {
    Path     string
    Size     int64
    LineCount int
    Empty    bool
}

// NewFileStat là constructor có validation.
func NewFileStat(path string, size int64) (FileStat, error) {
    if path == "" {
        return FileStat{}, fmt.Errorf("path cannot be empty")
    }
    if size < 0 {
        return FileStat{}, fmt.Errorf("size cannot be negative: %d", size)
    }
    return FileStat{Path: path, Size: size, Empty: size == 0}, nil
}
```
