// reporter/reporter.go
package reporter

func PrintTable(w io.Writer, summary analyzer.Summary) {
    fmt.Fprintf(w, "Total files: %d\n", summary.TotalFiles)
    fmt.Fprintf(w, "Empty files: %d\n", summary.EmptyCount)
    fmt.Fprintf(w, "Total bytes: %d\n", summary.TotalBytes)

    // Word frequency: sort by count desc, then alpha
    keys := make([]string, 0, len(summary.WordFreq))
    for k := range summary.WordFreq { keys = append(keys, k) }
    sort.Strings(keys)
    fmt.Fprintln(w, "\nWord frequency:")
    for _, k := range keys {
        fmt.Fprintf(w, "  %s: %d\n", k, summary.WordFreq[k])
    }
}
