package functions

import (
    "fmt"
    "strconv"
)

// ParsePositive parse string, chỉ chấp nhận giá trị dương.
// contract: nếu lỗi, caller không dùng result
func ParsePositive(s string) (int, error) {
    n, err := strconv.Atoi(s)
    if err != nil {
        return 0, fmt.Errorf("ParsePositive(%q): %w", s, err)
    }
    if n <= 0 {
        return 0, fmt.Errorf("ParsePositive: got %d, want > 0", n)
    }
    return n, nil
}
