// Named return RO BIỂT: chỉ khi có defer cần ghi
func OpenAndRead(path string) (content []byte, err error) {
    f, err := os.Open(path)
    if err != nil { return }  // naked return — rõ khi named
    defer func() {
        if cerr := f.Close(); cerr != nil && err == nil {
            err = cerr  // capture close error qua named return
        }
    }()
    return os.ReadFile(path)
}

// Named return TỆ, TRÁNH:
func BadNamed() (result int, err error) {
    // code dài, naked return làm khó đọc
    result = compute()
    return  // người đọc không biết result và err là gì!
}
```
