**EX B — Fan-out/fan-in (40 phút)**
File: `02_fanout.go`
```go
// Fan-out: 1 producer, N consumers
func fanOut(input <-chan int, n int) []<-chan int {
    outputs := make([]<-chan int, n)
    for i := 0; i < n; i++ {
        out := make(chan int)
        outputs[i] = out
        go func() {
            defer close(out)
            for v := range input { out <- v }
        }()
    }
    return outputs
}

// Fan-in: N producers, 1 consumer
func fanIn(channels ...<-chan int) <-chan int {
    var wg sync.WaitGroup
    merged := make(chan int)

    output := func(c <-chan int) {
        defer wg.Done()
        for v := range c { merged <- v }
    }

    wg.Add(len(channels))
    for _, c := range channels { go output(c) }

    go func() { wg.Wait(); close(merged) }()
    return merged
}
```
❓ Tại sao producer close channel, không phải consumer?

