```go
// select: chờ nhiều channel
select {
case msg := <-ch1:
    fmt.Println("got from ch1:", msg)
case msg := <-ch2:
    fmt.Println("got from ch2:", msg)
case <-time.After(1 * time.Second):
    fmt.Println("timeout")
}

// done channel pattern: cancellation
func worker(done <-chan struct{}) {
    for {
        select {
        case <-done:
            return  // signal to stop
        default:
            // do work
        }
    }
}
```
❓ Dùng `context.Context` thay vì done channel — lợi gì?

---

**EX D — Context cancellation (20 phút)**
```go
ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
defer cancel()  // ALWAYS defer cancel!

// Pass ctx vào function blocking
result, err := fetchData(ctx, url)
if err != nil {
    if errors.Is(err, context.DeadlineExceeded) {
        // timeout
    }
}
```
❓ Tại sao `defer cancel()` là best practice ngay cả khi không timeout sớm?

