**BƯỚC 1 — Concurrent parser stage (45 phút)**
```go
// pipeline/concurrent.go
func parseLinesConcurrent(ctx context.Context, lines <-chan string, workers int) <-chan ParseResult {
    out := make(chan ParseResult, workers)
    var wg sync.WaitGroup

    for i := 0; i < workers; i++ {
        wg.Add(1)
        go func() {
            defer wg.Done()
            for {
                select {
                case line, ok := <-lines:
                    if !ok { return }  // channel closed
                    result := ParseResult{Entry: parseOne(line)}
                    out <- result
                case <-ctx.Done():
                    return
                }
            }
        }()
    }

    go func() { wg.Wait(); close(out) }()
    return out
}
```

