**BƯỚC 1 — Retry window (20 phút)**
```go
// Một số error đáng thử lại (transient):
func withRetry(ctx context.Context, fn func() error, maxAttempts int) error {
    for i := 0; i < maxAttempts; i++ {
        if err := fn(); err == nil {
            return nil
        }
        select {
        case <-ctx.Done():
            return ctx.Err()
        case <-time.After(time.Duration(i+1) * 100 * time.Millisecond):
            // exponential-ish backoff
        }
    }
    return fmt.Errorf("failed after %d attempts", maxAttempts)
}
```

